import React, { useState } from 'react';
import { HomeScreen } from './screens/HomeScreen';
import GoalsScreen from './screens/GoalsScreen';
import LoansScreen from './screens/LoansScreen';
import ProfileScreen from './screens/ProfileScreen';

import NestLogo from './components/NestLogo';
import ProgressBar from './components/ProgressBar';
import { formatCurrency } from './helpers/helpers';
import { 
  Home, Target, User, Banknote, ArrowUpRight, ArrowDownLeft, Bell, X 
} from 'lucide-react';

// --- Mock Data ---
const INITIAL_GOALS = [
  { id: 1, title: 'New Laptop', current: 1200, target: 2000, color: 'bg-blue-500', icon: '💻', started:'Oct 1', lastSaved:'Oct 18', nextSave:'Oct 25' },
  { id: 2, title: 'Bali Trip', current: 850, target: 3000, color: 'bg-teal-500', icon: '✈️', started:'Sep 20', lastSaved:'Oct 20', nextSave:'Oct 27' },
];

const INITIAL_LOANS = [
  { id: 101, title: 'Emergency Cash', amount: 500, repaid: 150, totalDue: 550, dueDate: 'Nov 24', status: 'active', taken:'Oct 21' }
];

const TRANSACTIONS = [
  { id: 1, type: 'deposit', title: 'Salary Deposit', amount: 3500, date: 'Oct 24' },
  { id: 2, type: 'withdrawal', title: 'Rent Payment', amount: 1200, date: 'Oct 22' },
  { id: 3, type: 'loan', title: 'Loan Disbursement', amount: 500, date: 'Oct 21' },
];

export default function App() {
  // --- App State ---
  const [view, setView] = useState('app'); // splash, signin, signup, app
  const [activeTab, setActiveTab] = useState('home');
  const [balance, setBalance] = useState(12450.00);
  const [goals, setGoals] = useState(INITIAL_GOALS);
  const [loans, setLoans] = useState(INITIAL_LOANS);
  const [transactions, setTransactions] = useState(TRANSACTIONS);
  const [userName, setUserName] = useState('Alex');
  const [modal, setModal] = useState(null); // deposit, withdraw, goalDetail, loanDetail, addGoal, takeLoan
  const [selectedGoal, setSelectedGoal] = useState(null);
  const [selectedLoan, setSelectedLoan] = useState(null);

  // --- Helpers ---
  const getGreeting = () => {
    const hour = new Date().getHours();
    if(hour < 12) return 'Good Morning';
    if(hour < 18) return 'Good Afternoon';
    return 'Good Evening';
  }

  const handleTransactionAdd = (type, amount, title) => {
    const newTx = { id: Date.now(), type, title, amount, date: new Date().toLocaleDateString() };
    setTransactions([newTx, ...transactions]);
    setBalance(prev => type==='deposit'? prev + amount : prev - amount);
  }

  const handleSaveToGoal = (goalId, amount) => {
    if(amount <=0) return;
    setGoals(goals.map(g=>{
      if(g.id===goalId){
        return {...g, current: g.current + amount, lastSaved: new Date().toLocaleDateString(), nextSave: new Date(new Date().setDate(new Date().getDate()+7)).toLocaleDateString()};
      }
      return g;
    }));
    setBalance(balance - amount);
    setTransactions([{id:Date.now(), type:'deposit', title:`Saved to ${goals.find(g=>g.id===goalId).title}`, amount, date:new Date().toLocaleDateString()}, ...transactions]);
  }

  // --- Render Current Screen ---
  const renderScreen = () => {
    switch(activeTab) {
      case 'home':
        return <HomeScreen balance={balance} setModal={setModal} getGreeting={getGreeting} userName={userName} transactions={transactions} />;
      case 'goals':
        return <GoalsScreen goals={goals} setModal={setModal} setSelectedGoal={setSelectedGoal} />;
      case 'loans':
        return <LoansScreen loans={loans} setModal={setModal} setSelectedLoan={setSelectedLoan} />;
      case 'profile':
        return <ProfileScreen userName={userName} />;
      default:
        return null;
    }
  }

  // --- Bottom Navigation ---
  const navItems = [
    { key: 'home', label: 'Home', icon: <Home className="w-6 h-6" /> },
    { key: 'goals', label: 'Goals', icon: <Target className="w-6 h-6" /> },
    { key: 'loans', label: 'Loans', icon: <Banknote className="w-6 h-6" /> },
    { key: 'profile', label: 'Profile', icon: <User className="w-6 h-6" /> },
  ];

  // --- MODAL COMPONENT ---
  const renderModal = () => {
    if(!modal) return null;

    // Deposit / Withdraw Modal
    if(modal==='deposit' || modal==='withdraw'){
      const isDeposit = modal==='deposit';
      const [amount,setAmount] = useState('');
      return (
        <div className="absolute inset-0 bg-white p-6 z-30 overflow-y-auto">
          <button onClick={()=>setModal(null)} className="mb-4 p-2"><X className="w-6 h-6"/></button>
          <h2 className="text-2xl font-bold mb-4">{isDeposit?'Deposit Funds':'Withdraw Funds'}</h2>
          <input type="number" placeholder="Enter amount" value={amount} onChange={e=>setAmount(Number(e.target.value))} className="w-full p-3.5 border rounded-2xl mb-4 outline-none"/>
          <button onClick={()=>{
            if(amount>0){
              handleTransactionAdd(isDeposit?'deposit':'withdrawal', amount, isDeposit?'Deposit':'Withdrawal');
              setModal(null);
            }
          }} className="w-full bg-emerald-600 text-white py-3 rounded-2xl font-bold">{isDeposit?'Deposit':'Withdraw'}</button>
        </div>
      )
    }

    return null; // other modals can be added modularly like Goals and Loans
  }

  return (
    <div className="min-h-screen bg-gray-100 flex justify-center items-center font-sans p-4">
      <div className="w-full max-w-md h-[800px] bg-white rounded-[3rem] relative shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden flex flex-col border-[8px] border-gray-900">
        <div className="flex-1 overflow-y-auto scrollbar-hide">
          {view==='app' && renderScreen()}
        </div>

        {/* Bottom Navigation */}
        <nav className="absolute bottom-6 left-0 right-0 flex justify-between items-center px-10">
          {navItems.map(item => (
            <button key={item.key} onClick={()=>setActiveTab(item.key)} className="flex flex-col items-center gap-1">
              {React.cloneElement(item.icon, { className: `w-6 h-6 ${activeTab===item.key?'text-emerald-600':'text-gray-400'}` })}
              <span className={`text-xs ${activeTab===item.key?'text-emerald-600':'text-gray-400'}`}>{item.label}</span>
            </button>
          ))}
        </nav>

        {renderModal()}
      </div>
    </div>
  );
}
